import express, { Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Product } from './entity/Product'; // Adjust the path to your entity

const app = express();
app.use(express.json());

app.get('/api/products', async (req: Request, res: Response) => {
    const { name, category, minPrice, maxPrice } = req.query;
    let query = `SELECT * FROM product`;

    if (name) {
        query += ` WHERE name LIKE '%${name}%'`;
    }
    if (category) {
        query += ` AND category = '${category}'`;
    }
    if (minPrice) {
        query += ` AND price >= ${parseInt(minPrice as string)}`;
    }
    if (maxPrice) {
        query += ` AND price <= ${parseInt(maxPrice as string)}`;
    }

    try {
        const products = await getRepository(Product).query(query);
        res.json(products);
    } catch (error) {
        res.status(500).json({ error: 'Failed to fetch products' });
    }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});